import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { getAuthHeader } from "@/lib/auth";
import type { ContactMessage } from "@shared/schema";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { useToast } from "@/hooks/use-toast";
import { MessageSquare, Mail, Phone, User, Trash2, Eye, CheckCheck, Clock } from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";

const statusConfig: Record<string, { label: string; variant: "default" | "secondary" | "outline" }> = {
  NUEVO: { label: "Nuevo", variant: "default" },
  LEIDO: { label: "Leído", variant: "secondary" },
  RESPONDIDO: { label: "Respondido", variant: "outline" },
};

export default function MessagesManagement() {
  const { toast } = useToast();

  const { data: messages = [], isLoading } = useQuery<ContactMessage[]>({
    queryKey: ["/api/admin/messages"],
    queryFn: async () => {
      const response = await fetch("/api/admin/messages", { headers: getAuthHeader() });
      if (!response.ok) throw new Error("Error al cargar mensajes");
      return response.json();
    },
  });

  const updateStatusMutation = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: string }) => {
      await apiRequest("PUT", `/api/admin/messages/${id}/status`, { status });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/messages"] });
    },
    onError: () => {
      toast({ title: "Error", description: "No se pudo actualizar el estado", variant: "destructive" });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/admin/messages/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/messages"] });
      toast({ title: "Mensaje eliminado" });
    },
    onError: () => {
      toast({ title: "Error", description: "No se pudo eliminar el mensaje", variant: "destructive" });
    },
  });

  const newCount = messages.filter((m) => m.status === "NUEVO").length;

  if (isLoading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-32 w-full" />
        <Skeleton className="h-32 w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-2" data-testid="text-messages-title">
            <MessageSquare className="h-6 w-6 text-primary" />
            Mensajería
          </h2>
          <p className="text-muted-foreground">
            Mensajes de contacto recibidos desde la página principal
          </p>
        </div>
        {newCount > 0 && (
          <Badge data-testid="badge-new-messages">{newCount} nuevo{newCount > 1 ? "s" : ""}</Badge>
        )}
      </div>

      {messages.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <MessageSquare className="h-12 w-12 text-muted-foreground mb-4" />
            <p className="text-lg font-medium text-muted-foreground">No hay mensajes</p>
            <p className="text-sm text-muted-foreground">Los mensajes de contacto aparecerán aquí</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {messages.map((msg) => {
            const config = statusConfig[msg.status] || statusConfig.NUEVO;
            return (
              <Card key={msg.id} className={msg.status === "NUEVO" ? "border-primary/30" : ""} data-testid={`card-message-${msg.id}`}>
                <CardContent className="p-4 sm:p-6">
                  <div className="flex items-start justify-between gap-4 flex-wrap">
                    <div className="flex-1 min-w-0 space-y-3">
                      <div className="flex items-center gap-2 flex-wrap">
                        <Badge variant={config.variant} data-testid={`badge-status-${msg.id}`}>
                          {msg.status === "NUEVO" && <Clock className="h-3 w-3 mr-1" />}
                          {msg.status === "LEIDO" && <Eye className="h-3 w-3 mr-1" />}
                          {msg.status === "RESPONDIDO" && <CheckCheck className="h-3 w-3 mr-1" />}
                          {config.label}
                        </Badge>
                        <span className="text-xs text-muted-foreground">
                          {format(new Date(msg.createdAt), "dd MMM yyyy, HH:mm", { locale: es })}
                        </span>
                      </div>

                      <div className="grid gap-2 sm:grid-cols-3">
                        <div className="flex items-center gap-2 text-sm">
                          <User className="h-4 w-4 text-muted-foreground shrink-0" />
                          <span className="font-medium truncate" data-testid={`text-contact-name-${msg.id}`}>{msg.contactName}</span>
                        </div>
                        <div className="flex items-center gap-2 text-sm">
                          <Phone className="h-4 w-4 text-muted-foreground shrink-0" />
                          <span className="truncate" data-testid={`text-contact-phone-${msg.id}`}>{msg.phone}</span>
                        </div>
                        <div className="flex items-center gap-2 text-sm">
                          <Mail className="h-4 w-4 text-muted-foreground shrink-0" />
                          <span className="truncate" data-testid={`text-contact-email-${msg.id}`}>{msg.email}</span>
                        </div>
                      </div>

                      <div className="rounded-md bg-muted/50 p-3">
                        <p className="text-sm whitespace-pre-wrap" data-testid={`text-contact-comments-${msg.id}`}>{msg.comments}</p>
                      </div>
                    </div>

                    <div className="flex items-center gap-1 shrink-0">
                      {msg.status === "NUEVO" && (
                        <Button
                          size="icon"
                          variant="ghost"
                          onClick={() => updateStatusMutation.mutate({ id: msg.id, status: "LEIDO" })}
                          title="Marcar como leído"
                          data-testid={`button-mark-read-${msg.id}`}
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                      )}
                      {msg.status === "LEIDO" && (
                        <Button
                          size="icon"
                          variant="ghost"
                          onClick={() => updateStatusMutation.mutate({ id: msg.id, status: "RESPONDIDO" })}
                          title="Marcar como respondido"
                          data-testid={`button-mark-replied-${msg.id}`}
                        >
                          <CheckCheck className="h-4 w-4" />
                        </Button>
                      )}
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => deleteMutation.mutate(msg.id)}
                        title="Eliminar mensaje"
                        data-testid={`button-delete-message-${msg.id}`}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

client/src/pages/admin/statistics.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Target, Users, Trophy, TrendingUp } from "lucide-react";
import { getAuthHeader } from "@/lib/auth";
import type { Tournament, Player, Team } from "@shared/schema";
import { useState } from "react";

interface TopScorer {
  playerId: string;
  playerName: string;
  teamId: string;
  teamName: string;
  goals: number;
  photoUrl?: string;
}

export default function StatisticsManagement() {
  const [selectedTournamentId, setSelectedTournamentId] = useState<string>("all");

  const { data: tournaments = [] } = useQuery<Tournament[]>({
    queryKey: ["/api/admin/tournaments"],
    queryFn: async () => {
      const response = await fetch("/api/admin/tournaments", { headers: getAuthHeader() });
      if (!response.ok) throw new Error("Error al cargar torneos");
      return response.json();
    },
  });

  const { data: players = [] } = useQuery<Player[]>({
    queryKey: ["/api/admin/players"],
    queryFn: async () => {
      const response = await fetch("/api/admin/players", { headers: getAuthHeader() });
      if (!response.ok) throw new Error("Error al cargar jugadores");
      return response.json();
    },
  });

  const { data: teams = [] } = useQuery<Team[]>({
    queryKey: ["/api/admin/teams"],
    queryFn: async () => {
      const response = await fetch("/api/admin/teams", { headers: getAuthHeader() });
      if (!response.ok) throw new Error("Error al cargar equipos");
      return response.json();
    },
  });

  // Fetch real scorer data from API
  const tournamentQueryParam = selectedTournamentId !== "all" ? `?tournamentId=${selectedTournamentId}` : "";

  const { data: topScorers = [], isLoading: loadingScorers } = useQuery<TopScorer[]>({
    queryKey: ["/api/home/scorers", selectedTournamentId],
    queryFn: async () => {
      const response = await fetch(`/api/home/scorers${tournamentQueryParam}`);
      if (!response.ok) throw new Error("Error al cargar goleadores");
      return response.json();
    },
  });

  const activeTournaments = tournaments.filter(t => t.status === "ACTIVO");
  const totalGoals = topScorers.reduce((sum, s) => sum + s.goals, 0);

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h2 className="text-xl font-bold">Estadísticas Generales</h2>
          <p className="text-sm text-muted-foreground">
            Tabla de goleadores y estadísticas del torneo
          </p>
        </div>
        <Select value={selectedTournamentId} onValueChange={setSelectedTournamentId}>
          <SelectTrigger className="w-[200px]" data-testid="select-tournament-filter">
            <SelectValue placeholder="Filtrar por torneo" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Todos los torneos</SelectItem>
            {activeTournaments.map((t) => (
              <SelectItem key={t.id} value={t.id}>
                {t.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <Card data-testid="stat-total-players">
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-primary/10">
                <Users className="h-6 w-6 text-primary" />
              </div>
              <div>
                <p className="text-2xl font-bold">{players.length}</p>
                <p className="text-sm text-muted-foreground">Jugadores Totales</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card data-testid="stat-total-teams">
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-primary/10">
                <Trophy className="h-6 w-6 text-primary" />
              </div>
              <div>
                <p className="text-2xl font-bold">{teams.length}</p>
                <p className="text-sm text-muted-foreground">Equipos Totales</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card data-testid="stat-total-goals">
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-primary/10">
                <Target className="h-6 w-6 text-primary" />
              </div>
              <div>
                <p className="text-2xl font-bold">
                  {totalGoals}
                </p>
                <p className="text-sm text-muted-foreground">Goles Totales</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card data-testid="stat-top-scorer">
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-primary/10">
                <TrendingUp className="h-6 w-6 text-primary" />
              </div>
              <div>
                <p className="text-lg font-bold truncate">
                  {topScorers[0]?.playerName || "N/A"}
                </p>
                <p className="text-sm text-muted-foreground">
                  Máximo Goleador ({topScorers[0]?.goals || 0} goles)
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Target className="h-5 w-5 text-primary" />
            Tabla de Goleadores
          </CardTitle>
        </CardHeader>
        <CardContent>
          {loadingScorers ? (
            <div className="space-y-3">
              {[1, 2, 3, 4, 5].map(i => <Skeleton key={i} className="h-12" />)}
            </div>
          ) : topScorers.length === 0 ? (
            <div className="py-12 text-center text-muted-foreground">
              <Target className="mx-auto h-12 w-12 opacity-50" />
              <p className="mt-4">No hay goleadores registrados</p>
              <p className="text-sm">Los goles se registran cuando el árbitro finaliza un partido</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b text-muted-foreground">
                    <th className="pb-3 text-left font-medium w-12">#</th>
                    <th className="pb-3 text-left font-medium">Jugador</th>
                    <th className="pb-3 text-left font-medium">Equipo</th>
                    <th className="pb-3 text-center font-medium w-20">Goles</th>
                  </tr>
                </thead>
                <tbody>
                  {topScorers.map((scorer, idx) => (
                    <tr
                      key={scorer.playerId}
                      className={`border-b last:border-0 ${idx < 3 ? "bg-primary/5" : ""}`}
                      data-testid={`row-scorer-${idx + 1}`}
                    >
                      <td className="py-3 font-bold">
                        {idx < 3 ? (
                          <div className={`flex h-7 w-7 items-center justify-center rounded-full text-xs font-bold ${
                            idx === 0 ? "bg-primary text-primary-foreground" :
                            idx === 1 ? "bg-muted text-foreground" :
                            "bg-secondary text-secondary-foreground"
                          }`}>
                            {idx + 1}
                          </div>
                        ) : (
                          <span className="text-muted-foreground pl-2">{idx + 1}</span>
                        )}
                      </td>
                      <td className="py-3">
                        <div className="flex items-center gap-3">
                          {scorer.photoUrl ? (
                            <img 
                              src={scorer.photoUrl} 
                              alt={scorer.playerName}
                              className="h-9 w-9 rounded-full object-cover"
                            />
                          ) : (
                            <div className="flex h-9 w-9 items-center justify-center rounded-full bg-primary text-primary-foreground font-bold text-sm">
                              {scorer.playerName.charAt(0)}
                            </div>
                          )}
                          <span className="font-medium">{scorer.playerName}</span>
                        </div>
                      </td>
                      <td className="py-3 text-muted-foreground">{scorer.teamName}</td>
                      <td className="py-3 text-center">
                        <Badge variant="default" className="text-sm font-bold px-3">
                          {scorer.goals}
                        </Badge>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

