    for (const row of result.rows) {
      if (!row.a_id) continue;
      let match: MatchWithTeams | undefined;
      if (row.matchId) {
        match = await this.getMatchWithTeams(row.matchId);
      }
      newsItems.push({
        id: row.id,
        tournamentId: row.tournamentId,
        matchId: row.matchId,
        title: row.title,
        content: row.content,
        imageUrl: row.imageUrl,
        authorId: row.authorId,
